/**
 * Category Utilities Tests
 *
 * Tests for category and subtype parsing utility functions used across
 * classification stages.
 */

import {
  getCategoryKey,
  getSubtypeKey,
  areSubtypesOfSameCategory,
  parseCategoryName,
} from '../../src/utils/category-utils';

describe('Category Utilities', () => {
  describe('getCategoryKey', () => {
    it('should extract category from category-only name', () => {
      expect(getCategoryKey('FINANCE')).toBe('FINANCE');
    });

    it('should extract category from category.subtype name', () => {
      expect(getCategoryKey('FINANCE.BANKING')).toBe('FINANCE');
    });

    it('should handle multiple dots (use first segment)', () => {
      expect(getCategoryKey('FINANCE.BANKING.CHECKING')).toBe('FINANCE');
    });

    it('should handle empty string', () => {
      expect(getCategoryKey('')).toBe('');
    });

    it('should preserve case', () => {
      expect(getCategoryKey('Finance.Banking')).toBe('Finance');
    });

    it('should handle names with no dots', () => {
      expect(getCategoryKey('SHOPPING')).toBe('SHOPPING');
    });
  });

  describe('getSubtypeKey', () => {
    it('should return null for category-only name', () => {
      expect(getSubtypeKey('FINANCE')).toBeNull();
    });

    it('should extract subtype from category.subtype name', () => {
      expect(getSubtypeKey('FINANCE.BANKING')).toBe('BANKING');
    });

    it('should extract first subtype from multiple dots', () => {
      expect(getSubtypeKey('FINANCE.BANKING.CHECKING')).toBe('BANKING');
    });

    it('should return null for empty string', () => {
      expect(getSubtypeKey('')).toBeNull();
    });

    it('should preserve subtype case', () => {
      expect(getSubtypeKey('Finance.Banking')).toBe('Banking');
    });

    it('should handle subtype with special characters', () => {
      expect(getSubtypeKey('CATEGORY.SUB_TYPE')).toBe('SUB_TYPE');
    });
  });

  describe('areSubtypesOfSameCategory', () => {
    it('should return true for subtypes of same category', () => {
      expect(areSubtypesOfSameCategory('FINANCE.BANKING', 'FINANCE.INVESTING')).toBe(true);
    });

    it('should return false for subtypes of different categories', () => {
      expect(areSubtypesOfSameCategory('FINANCE.BANKING', 'SHOPPING.ONLINE')).toBe(false);
    });

    it('should return false if first is category-only', () => {
      expect(areSubtypesOfSameCategory('FINANCE', 'FINANCE.BANKING')).toBe(false);
    });

    it('should return false if second is category-only', () => {
      expect(areSubtypesOfSameCategory('FINANCE.BANKING', 'FINANCE')).toBe(false);
    });

    it('should return false if both are category-only', () => {
      expect(areSubtypesOfSameCategory('FINANCE', 'SHOPPING')).toBe(false);
    });

    it('should return false if both are category-only but same category', () => {
      expect(areSubtypesOfSameCategory('FINANCE', 'FINANCE')).toBe(false);
    });

    it('should be case-sensitive for category comparison', () => {
      expect(areSubtypesOfSameCategory('FINANCE.BANKING', 'finance.investing')).toBe(false);
    });

    it('should handle multiple-level subtypes', () => {
      expect(areSubtypesOfSameCategory('FINANCE.BANKING.CHECKING', 'FINANCE.INVESTING.STOCKS')).toBe(true);
    });
  });

  describe('parseCategoryName', () => {
    it('should parse category-only name', () => {
      const result = parseCategoryName('FINANCE');
      expect(result).toEqual({
        category: 'FINANCE',
        subtype: null,
        hasSubtype: false,
        fullName: 'FINANCE',
      });
    });

    it('should parse category.subtype name', () => {
      const result = parseCategoryName('FINANCE.BANKING');
      expect(result).toEqual({
        category: 'FINANCE',
        subtype: 'BANKING',
        hasSubtype: true,
        fullName: 'FINANCE.BANKING',
      });
    });

    it('should handle multiple dots (only first two segments)', () => {
      const result = parseCategoryName('FINANCE.BANKING.CHECKING');
      expect(result).toEqual({
        category: 'FINANCE',
        subtype: 'BANKING',
        hasSubtype: true,
        fullName: 'FINANCE.BANKING.CHECKING',
      });
    });

    it('should handle empty string', () => {
      const result = parseCategoryName('');
      expect(result).toEqual({
        category: '',
        subtype: null,
        hasSubtype: false,
        fullName: '',
      });
    });

    it('should preserve original case', () => {
      const result = parseCategoryName('Finance.Banking');
      expect(result).toEqual({
        category: 'Finance',
        subtype: 'Banking',
        hasSubtype: true,
        fullName: 'Finance.Banking',
      });
    });

    it('should handle names with trailing dots', () => {
      const result = parseCategoryName('FINANCE.');
      expect(result).toEqual({
        category: 'FINANCE',
        subtype: '',
        hasSubtype: true,
        fullName: 'FINANCE.',
      });
    });
  });

  describe('Edge Cases and Integration', () => {
    it('should handle null/undefined gracefully with type checking', () => {
      // TypeScript would catch these at compile time, but test runtime behavior
      expect(() => getCategoryKey(null as unknown as string)).not.toThrow();
      expect(() => getSubtypeKey(undefined as unknown as string)).not.toThrow();
    });

    it('should work with real category examples', () => {
      const categories = ['FINANCE.BANKING', 'FINANCE.INVESTING', 'SHOPPING.ONLINE', 'TRAVEL.FLIGHTS', 'PERSONAL'];

      categories.forEach((cat) => {
        const parsed = parseCategoryName(cat);
        expect(parsed.category).toBe(getCategoryKey(cat));
        expect(parsed.subtype).toBe(getSubtypeKey(cat));
      });
    });

    it('should maintain consistency between parsing functions', () => {
      const testCases = ['CATEGORY', 'CATEGORY.SUBTYPE', 'A.B.C', ''];

      testCases.forEach((testCase) => {
        const parsed = parseCategoryName(testCase);
        expect(parsed.category).toBe(getCategoryKey(testCase));
        expect(parsed.subtype).toBe(getSubtypeKey(testCase));
        expect(parsed.hasSubtype).toBe(getSubtypeKey(testCase) !== null);
      });
    });
  });
});

