  it('should handle empty batch gracefully', async () => {
    const results = new Map<string, ClassificationResult>();

    await expect(saveClassificationBatch(results)).rejects.toThrow('Batch is empty - no results to persist');
  });

  it('should track batch processing performance', async () => {
    const results = new Map<string, ClassificationResult>();

    results.set('perf-test-1', {
      selectedLabels: [
        {
          category: 'FINANCIAL',
          subtype: null,
          confidence: 95,
          score: 0.95,
          isPrimary: true,
          labelOrder: 1,
          selectionRationale: 'Financial',
        },
      ],
      candidateScores: {
        FINANCIAL: { score: 0.95, confidence: 95, decision: 'selected' },
      },
      selectionSummary: {
        totalLabels: 1,
        primaryCategory: 'FINANCIAL',
        confidenceRange: [95, 95],
        selectionMethod: 'single_label',
        needsAi: false,
      },
      needsAiClassification: false,
      processingDurationMs: 1200,
    } as unknown as ClassificationResult);

    mockQuery
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // BEGIN
      .mockResolvedValueOnce({ rows: [{ session_id: 3001 }], rowCount: 1 }) // INSERT session
      .mockResolvedValueOnce({ rows: [{ stage_id: 301 }], rowCount: 1 }) // INSERT stage
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // INSERT eval
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }); // COMMIT

    const startTime = Date.now();
    await saveClassificationBatch(results);
    const duration = Date.now() - startTime;

    expect(duration).toBeGreaterThanOrEqual(0);
  });
});

